<template><el-card><template #header>业务专家工作台：自然语言创建技能</template><div class="two-col"><el-card><template #header>专家输入</template><el-input v-model="prompt" type="textarea" :rows="12"/><div class="actions"><el-button @click="prompt=sample">填入示例</el-button><el-button type="primary" :loading="loading" @click="generate">生成技能草案</el-button></div></el-card><el-card><template #header>AI 生成结果预览</template><EmptyState v-if="!draft" description="请先生成技能草案"/><el-descriptions v-else :column="1" border><el-descriptions-item v-for="(v,k) in draft" :key="k" :label="String(k)">{{Array.isArray(v)?v.join('、'):v}}</el-descriptions-item></el-descriptions><div v-if="draft" class="actions"><el-button @click="generate">重新生成</el-button><el-button @click="saved=true">保存草稿</el-button><el-button type="warning" @click="submitted=true">提交审核</el-button></div><el-alert v-if="saved" title="技能草稿已保存" type="success" class="mt"/><el-alert v-if="submitted" title="技能草案已提交审核" type="warning" class="mt"/></el-card></div></el-card></template>
<script setup lang="ts">import { ref } from 'vue'; import { api } from '@/api'; import EmptyState from '@/components/EmptyState.vue'; const sample='创建一个光伏并网导办技能，适用于自然人用户，能够回答办理材料、并网流程、注意事项。'; const prompt=ref(sample); const draft=ref<any>(); const loading=ref(false); const saved=ref(false); const submitted=ref(false); async function generate(){loading.value=true; draft.value=await api.generateSkill(); loading.value=false; saved.value=false; submitted.value=false}</script>
